import{_ as n,c as s,o as l,ae as e}from"./chunks/framework.BTGIOJIj.js";const d=JSON.parse('{"title":"作用域和作用域链","description":"","frontmatter":{},"headers":[],"relativePath":"document/closure.md","filePath":"document/closure.md"}'),i={name:"document/closure.md"};function o(p,a,t,r,c,u){return l(),s("div",null,a[0]||(a[0]=[e(`<h1 id="作用域和作用域链" tabindex="-1">作用域和作用域链 <a class="header-anchor" href="#作用域和作用域链" aria-label="Permalink to &quot;作用域和作用域链&quot;">​</a></h1><p>概念：在JavaScript里，函数、块、模块都可以形成作用域（一个存放变量的独立空间），他们之间可以相互嵌套，作用域之间会形成引用关系，这条链叫做作用域链。作用域分为静态作用域和动态作用域，作用域链分为静态作用域链和动态作用域链。JS语言是静态作用域，JS的作用域链是静态作用域链。</p><ul><li>静态作用域: 函数被定义的那一刻，函数中变量的查找范围就确定了，取决于函数的定义位置。可以静态分析出整条作用域链中的变量关系。 -- 可以延伸到闭包、GC垃圾回收(标记清除)</li><li>动态作用域: 函数被执行时，函数中变量的查找范围才确定，取决于函数的执行位置。缺点是不直观，无法静态分析。</li></ul><h1 id="闭包" tabindex="-1">闭包 <a class="header-anchor" href="#闭包" aria-label="Permalink to &quot;闭包&quot;">​</a></h1><p>闭包是可以访问其它函数内部变量的函数 闭包的设计是为了解决子函数晚于父函数销毁的问题，js会在父函数销毁时，把子函数引用到的变量打包成Closure包放到函数的[Scopes]上，让它即使父函数销毁了也随时随地能访问外部环境。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>var x = 1;</span></span>
<span class="line"><span>var obj = {x:2}</span></span>
<span class="line"><span>obj.fn=(function(x){</span></span>
<span class="line"><span>  this.x*=x++;</span></span>
<span class="line"><span>  return function(y){</span></span>
<span class="line"><span>    x+=y;</span></span>
<span class="line"><span>    this.x*=++x;</span></span>
<span class="line"><span>    console.log(x);</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>})(obj.x);</span></span>
<span class="line"><span>var fn = obj.fn;</span></span>
<span class="line"><span>obj.fn(2);//6</span></span>
<span class="line"><span>fn(1);//8</span></span>
<span class="line"><span>console.log(obj.x,x);//false:24 8 true: 12 16</span></span></code></pre></div><h2 id="闭包的优点" tabindex="-1">闭包的优点 <a class="header-anchor" href="#闭包的优点" aria-label="Permalink to &quot;闭包的优点&quot;">​</a></h2><ul><li>可以保存变量，用于缓存</li><li>避免全局变量污染</li><li>加强封装性 让js也能支持私有变量</li></ul><h2 id="闭包的缺点" tabindex="-1">闭包的缺点 <a class="header-anchor" href="#闭包的缺点" aria-label="Permalink to &quot;闭包的缺点&quot;">​</a></h2><ul><li>大量使用时 内存消耗大 影响性能</li><li>过度使用时 可能会导致内存泄漏 或程序卡慢等 所以在退出函数之前应删除不使用的局部变量</li></ul><h2 id="闭包的应用" tabindex="-1">闭包的应用 <a class="header-anchor" href="#闭包的应用" aria-label="Permalink to &quot;闭包的应用&quot;">​</a></h2><ul><li>私有变量</li><li>回调计数器</li><li>柯里化函数、compose函数等高阶函数</li><li>防抖、节流</li><li>独立作用域、类库包装等</li></ul><h2 id="除闭包外还有哪些会导致内存泄漏" tabindex="-1">除闭包外还有哪些会导致内存泄漏 <a class="header-anchor" href="#除闭包外还有哪些会导致内存泄漏" aria-label="Permalink to &quot;除闭包外还有哪些会导致内存泄漏&quot;">​</a></h2><ul><li>意外的全局变量 （隐式全局变量）</li><li>定时器</li><li>脱离文档的DOM引用 引用了一个dom元素 元素被删除后 引用变量还存在</li><li>未销毁的交叉观察对象Intersection API</li></ul><h2 id="如何检测内存泄漏" tabindex="-1">如何检测内存泄漏 <a class="header-anchor" href="#如何检测内存泄漏" aria-label="Permalink to &quot;如何检测内存泄漏&quot;">​</a></h2><ul><li>内存泄漏通常是由于闭包引起的</li><li>可用的检测手段： chrome devtool的Memory面板</li></ul>`,16)]))}const b=n(i,[["render",o]]);export{d as __pageData,b as default};
